const PRIORITY = [
  'PLANETS', 'ZODIAC', 'ELEMENTS', 'MAJOR_ARCANA', 'MINOR_ARCANA',
  'GEOMETRY', 'PHYSIOLOGY', 'CHAKRAS', 'KABBALAH', 'NUMBERS', 'FREQUENCY',
  'METALS', 'CRYSTALS', 'PLANTS',
  'DEITIES', 'I_CHING', 'GEOMANCY', 'LETTERS_HEBREW', 'LETTERS_LATIN',
  'ALCHEMY', 'VIRTUES', 'VICES'
];

const TONE_LABELS = {
  oracle: 'ORACLE',
  mythic: 'MYTHIC',
  alchemical: 'ALCHEMICAL',
  'clinical-symbolic': 'CLINICAL_SYMBOLIC',
  xenolinguistic: 'XENOLINGUISTIC'
};

const STREAM_LABELS = {
  dream: 'DREAM_LOGIC',
  chakra: 'CHAKRA_ASCENT',
  planetary: 'PLANETARY_DESCENT',
  elemental: 'ELEMENTAL_TRANSFORMATION'
};

function splitValues(value) {
  return String(value || '')
    .split(';')
    .map(item => item.trim())
    .filter(Boolean);
}

export function stripMeta(value) {
  return String(value || '')
    .replace(/[\u{1F000}-\u{1FAFF}\u{2600}-\u{27BF}]/gu, '')
    .replace(/\[[^\]]*]/g, '')
    .replace(/\([^)]*(other|gen|egyptian|greek|latin|hebrew|category)[^)]*\)/gi, '')
    .replace(/\b[IVXLCDM]{1,5}\s*[-\u2013\u2014]\s*/g, '')
    .replace(/\b\d{1,3}\s*[-\u2013\u2014]\s*/g, '')
    .replace(/\s{2,}/g, ' ')
    .trim();
}

function cleanValue(value, max = 3) {
  return splitValues(value).map(stripMeta).filter(Boolean).slice(0, max).join(', ');
}

function sentenceList(items) {
  const clean = items.filter(Boolean);
  if (clean.length <= 1) return clean[0] || '';
  if (clean.length === 2) return `${clean[0]} and ${clean[1]}`;
  return `${clean.slice(0, -1).join(', ')}, and ${clean.at(-1)}`;
}

export function fieldMap(correspondences = [], ownSystem = '') {
  const map = {};
  correspondences.forEach(row => {
    if (!row || row.system === ownSystem) return;
    const value = cleanValue(row.value);
    if (value) map[row.system] = { label: row.label || row.system, value };
  });
  return map;
}

export function strongestFields(correspondences = [], ownSystem = '', count = 10) {
  const rows = correspondences
    .filter(row => row && row.system !== ownSystem && row.value)
    .map(row => ({ ...row, value: cleanValue(row.value), priority: PRIORITY.indexOf(row.system) }))
    .filter(row => row.value);
  return rows
    .sort((a, b) => (a.priority < 0 ? 999 : a.priority) - (b.priority < 0 ? 999 : b.priority))
    .slice(0, count);
}

function anchor(map, key, fallback = '') {
  return map[key]?.value || fallback;
}

function motifLine(fields) {
  return fields.slice(0, 8).map(row => `${row.label}: ${row.value}`).join('; ');
}

function synthesisAnchors(payload) {
  const map = fieldMap(payload.correspondences, payload.system);
  const fields = strongestFields(payload.correspondences, payload.system, 10);
  return {
    map,
    fields,
    name: stripMeta(payload.name),
    system: payload.system_label || payload.system,
    planet: anchor(map, 'PLANETS', 'the governing light'),
    zodiac: anchor(map, 'ZODIAC', 'the zodiacal climate'),
    element: anchor(map, 'ELEMENTS', 'the elemental body'),
    tarot: anchor(map, 'MAJOR_ARCANA', anchor(map, 'MINOR_ARCANA', 'the inner image')),
    geometry: anchor(map, 'GEOMETRY', anchor(map, 'PLATONIC_SOLIDS', 'the hidden shape')),
    body: anchor(map, 'PHYSIOLOGY', anchor(map, 'CHAKRAS', 'the embodied gate')),
    chakra: anchor(map, 'CHAKRAS'),
    kabbalah: anchor(map, 'KABBALAH'),
    number: anchor(map, 'NUMBERS', anchor(map, 'FREQUENCY', 'the measure')),
    alchemy: anchor(map, 'ALCHEMY', 'transformation'),
    material: sentenceList([anchor(map, 'METALS'), anchor(map, 'CRYSTALS'), anchor(map, 'PLANTS')]),
    mythic: sentenceList([anchor(map, 'DEITIES'), anchor(map, 'I_CHING'), anchor(map, 'GEOMANCY'), anchor(map, 'LETTERS_HEBREW')]),
  };
}

