export function buildSynthesisFallback(payload, tone = 'mythic') {
  const a = synthesisAnchors(payload);
  const style = synthesisStyle(a, tone);
  return {
    mode: TONE_LABELS[tone] || 'MYTHIC',
    title: `${a.name} - ${TONE_LABELS[tone] || 'MYTHIC'} Synthesis`,
    spoken_title: a.name,
    display_text: `${style.display}\n\nSelected chamber anchors: ${motifLine(a.fields)}.`,
    guide_text: style.guide,
    narration_text: style.narration,
    speech_aliases: { [payload.name]: a.name },
    motifs: a.fields.slice(0, 5).map(row => row.label)
  };
}

function bridgeText(payload) {
  const bridge = payload.hidden_bridges?.[0] || payload.bridges?.[0];
  if (bridge) return stripMeta(bridge);
  const shared = payload.shared_fields?.[0];
  if (shared) return `${stripMeta(shared.field)} through ${(shared.values || []).map(stripMeta).filter(Boolean).join(', ')}`;
  return 'an indirect pressure neither side can name alone';
}

function sharedText(payload) {
  const rows = (payload.shared_fields || []).slice(0, 3).map(row => {
    const values = (row.values || []).map(stripMeta).filter(Boolean).slice(0, 3).join(', ');
    return values ? `${stripMeta(row.field)}: ${values}` : '';
  }).filter(Boolean);
  return rows.length ? rows.join('; ') : 'no obvious shared field';
}

function frictionText(payload) {
  const row = payload.frictions?.[0] || payload.tensions?.[0];
  if (!row) return 'their difference is atmospheric rather than literal';
  return `${stripMeta(row.field)}: ${stripMeta(row.left || row.a)} against ${stripMeta(row.right || row.b)}`;
}

