export function buildStreamFallback(payload) {
  const preset = String(payload.preset || 'dream').toLowerCase();
  const style = streamPresetStyle(preset, payload.sequence || []);
  const nodes = (payload.sequence || []).map((node, index, list) => {
    const name = stripMeta(node.name);
    const next = list[index + 1] ? stripMeta(list[index + 1].name) : 'the closing gate';
    const why = stripMeta(node.why || 'this symbol carries the previous pressure into a new chamber');
    return {
      node_name: node.name,
      spoken_name: name,
      display_text: node.why || `Gate ${index + 1}: ${name}`,
      guide_text: `${name} matters here because it changes the route's emotional pressure. It does not merely follow the previous symbol; it translates that symbol into a new kind of attention before the path moves toward ${next}.`,
      narration_text: `Gate ${index + 1} opens through ${name}. The path moves here because ${why}. Notice what becomes clearer, heavier, softer, or more alive as this chamber turns toward ${next}. This is the point where the journey stops being a map and becomes an experience in the body.`,
      transition_reason: node.why || `The path turns through ${name} toward ${next}.`
    };
  });
  const last = stripMeta(payload.sequence?.at(-1)?.name || 'the final gate');
  return {
    mode: STREAM_LABELS[preset] || 'DREAM_LOGIC',
    stream_title: style.title,
    stream_subtitle: STREAM_LABELS[preset] || preset,
    display_intro: style.display,
    guide_intro: style.guide,
    narration_intro: style.narration,
    nodes,
    closing_line: `${last} does not end the path; it leaves a changed pressure in the field.`,
    speech_aliases: Object.fromEntries((payload.sequence || []).map(node => [node.name, stripMeta(node.name)]))
  };
}
