import { requestStructuredMode } from './mode-api.js';
import { buildStreamPrompt } from './prompt-schemas.js';
import { bindGuideLayer, renderTextLayer, setGuideOpen } from './guide-layer.js';
import { buildStreamFallback } from './mode-prose.js';

const STREAM_PRESETS = [
  { id: 'dream', title: 'Dream Logic', length: 3 },
  { id: 'chakra', title: 'Chakra Ascent', length: 7 },
  { id: 'planetary', title: 'Planetary Descent', length: 6 },
  { id: 'elemental', title: 'Elemental Transformation', length: 5 }
];

const HUMAN_ID = 'stream-human';
const NARRATION_ID = 'stream-narration';

export function createStreamMode(ctx) {
  let controller = null;
  let lastSeedRef = null;
  let lastAllEntries = [];

  function collect(ref) {
    const name = ctx.getEntryName(ref.cat, ref.entry);
    return {
      cat: ref.cat,
      label: ctx.CAT_META[ref.cat]?.label || ref.cat,
      name,
      glyph: ctx.getGlyph(name, ref.cat),
      color: ctx.getColorForEntry(name, ref.cat),
      entry: ref.entry
    };
  }

  function linkedRefs(ref) {
    const out = [];
    ctx.fieldOrder(ref.entry, true).forEach(key => {
      if (key === ref.cat || !ctx.CODEX[key]) return;
      ctx.splitValues(ref.entry[key]).forEach(value => {
        const target = ctx.resolveEntryRef(key, value);
        if (target) out.push({ cat: target.cat, idx: target.idx, entry: target.entry, why: `${ctx.CAT_META[key]?.label || key}: ${value}` });
      });
    });
    return out;
  }

  function buildPath(seedRef, allEntries, preset, length) {
    if (!allEntries.length && !seedRef) return [];
    const path = [];
    const seen = new Set();
    let current = seedRef || allEntries[Math.floor(Math.random() * allEntries.length)];
    for (let i = 0; i < length; i++) {
      const key = `${current.cat}:${current.idx}`;
      if (!seen.has(key)) {
        path.push({ ...current, why: current.why || (i === 0 ? `The gate opens through ${ctx.CAT_META[current.cat]?.label || current.cat}.` : 'The lattice turns through correspondence.') });
        seen.add(key);
      }
      const links = linkedRefs(current).filter(ref => !seen.has(`${ref.cat}:${ref.idx}`));
      if (preset === 'chakra') {
        const chakra = links.find(ref => ref.cat === 'CHAKRAS');
        if (chakra) { current = chakra; continue; }
      }
      if (preset === 'planetary') {
        const planet = links.find(ref => ref.cat === 'PLANETS');
        if (planet) { current = planet; continue; }
      }
      if (preset === 'elemental') {
        const element = links.find(ref => ref.cat === 'ELEMENTS' || ref.cat === 'ALCHEMY');
        if (element) { current = element; continue; }
      }
      current = links[0] || allEntries[Math.floor(Math.random() * allEntries.length)] || current;
    }
    return path;
  }

  function fallback(payload) {
    return buildStreamFallback(payload);
  }

  function normalizeResult(result, payload) {
    const nodes = result.nodes?.length ? result.nodes : (result.sequence || payload.sequence || []).map((node, index) => ({
      node_name: node.node_name || node.name,
      spoken_name: node.spoken_name || node.name,
      display_text: node.display_text || node.why || `Gate ${index + 1}: ${node.name}`,
      guide_text: node.guide_text || node.why || 'This point matters because it changes the path from one symbolic chamber to the next.',
      narration_text: node.narration_text || node.why || node.name,
      transition_reason: node.transition_reason || node.why || ''
    }));
    return {
      ...result,
      stream_title: result.stream_title || result.title || payload.title,
      stream_subtitle: result.stream_subtitle || result.tone || payload.preset,
      display_intro: result.display_intro || result.short_reading || '',
      guide_intro: result.guide_intro || 'This path turns separate correspondences into a sequence you can follow.',
      narration_intro: result.narration_intro || result.audio_text || 'The stream narration transcript is pending.',
      nodes,
      speech_aliases: result.speech_aliases || {}
    };
  }

  function renderLoading(payload) {
    const overlay = document.getElementById('streamOverlay');
    overlay.innerHTML = `<div class="stream-card initiatory-card">
      <div class="mode-kicker">INITIATORY STREAM</div>
      <div class="mode-title">${ctx.escapeHTML(payload.title)}</div>
      <div class="ritual-loader"><span></span><span></span><span></span></div>
      <div class="mode-copy">Selecting linked chambers and binding transition logic...</div>
    </div>`;
    overlay.classList.add('on');
  }

  function renderLocked(result) {
    const overlay = document.getElementById('streamOverlay');
    overlay.innerHTML = `<div class="stream-card initiatory-card">
      <button class="card-close-btn mode-close" data-stream-close>X</button>
      <div class="mode-kicker">INITIATE GATE</div>
      <div class="mode-title">The longer stream is sealed.</div>
      <div class="mode-copy">Your ${ctx.escapeHTML(result.gate.plan)} stream allotment is complete. Create a free account for a daily short stream; Initiate unlocks long-form narrated journeys.</div>
      <button class="mode-btn-primary" data-mode-upgrade>CREATE FREE ACCOUNT</button>
    </div>`;
    overlay.classList.add('on');
    bindStatic();
  }

  function render(payload, result, index = 0) {
    result = normalizeResult(result, payload);
    const overlay = document.getElementById('streamOverlay');
    const node = payload.sequence[index] || payload.sequence[0];
    const resultNode = result.nodes[index] || result.nodes[0] || {};
    if (!node) {
      renderLoading({ title: 'Dream Logic Stream' });
      return;
    }
    const why = resultNode.transition_reason || node.why || 'The path continues through an unseen correspondence.';
    const presets = STREAM_PRESETS.map(p => `<button class="mode-chip ${p.id === payload.preset ? 'active' : ''}" data-stream-preset="${p.id}">${p.title}</button>`).join('');
    const rail = payload.sequence.map((step, i) => `<button class="stream-node ${i === index ? 'active' : ''}" data-stream-step="${i}" style="--c:${step.color}"><span>${step.glyph}</span><b>${ctx.escapeHTML(step.name)}</b></button>`).join('');
    const narrationText = index === 0
      ? [result.narration_intro, resultNode.narration_text].filter(Boolean).join('\n\n')
      : (resultNode.narration_text || result.narration_intro || '');
    overlay.innerHTML = `<div class="stream-card initiatory-card">
      <button class="card-close-btn mode-close" data-stream-close>X</button>
      <div class="mode-kicker">INITIATORY STREAM</div>
      <div class="mode-title">${ctx.escapeHTML(result.stream_title || payload.title)}</div>
      <div class="mode-sub">${ctx.escapeHTML(result.stream_subtitle || payload.preset)}</div>
      <div class="mode-tone-row">${presets}</div>
      <div class="stream-rail">${rail}</div>
      <div class="stream-focus" style="--c:${node.color}">
        <div class="mode-glyph">${node.glyph}</div>
        <div>
          <div class="stream-focus-name">${ctx.escapeHTML(node.name)}</div>
          <div class="mode-sub">${ctx.escapeHTML(node.label)}</div>
          <div class="mode-reading short occult-gate">${ctx.escapeHTML(resultNode.display_text || why)}</div>
        </div>
      </div>
      ${renderTextLayer({ id: HUMAN_ID, label: 'Human Reading - Why this part of the journey matters', text: resultNode.guide_text || result.guide_intro, open: true, variant: 'human' })}
      ${renderTextLayer({ id: NARRATION_ID, label: 'Narration Transcript', text: narrationText, open: true, variant: 'narration' })}
      <div class="mode-reading stream-intro">${ctx.escapeHTML(index === 0 ? (result.display_intro || '') : why).replace(/\n/g, '<br><br>')}</div>
      <div class="mode-actions">
        <button class="mode-btn" data-stream-prev>PREV</button>
        <button class="mode-btn-primary" data-mode-audio>PLAY GUIDE</button>
        <button class="mode-btn" data-stream-next>NEXT</button>
        <button class="mode-btn" data-stream-close>CLOSE</button>
      </div>
      <div class="mode-quota">${formatGate(result.gate)}</div>
    </div>`;
    overlay.classList.add('on');
    bind(result, payload, index);
  }

  function formatGate(gate) {
    if (!gate) return '';
    if (gate.plan === 'admin') return 'Admin test mode / long-form stream unsealed';
    if (gate.remaining === 'unlimited') return 'Initiate access / long-form stream';
    return `${gate.remaining} stream journey${gate.remaining === 1 ? '' : 's'} remaining for ${gate.plan}`;
  }

  function bindStatic() {
    const overlay = document.getElementById('streamOverlay');
    overlay.querySelectorAll('[data-stream-close]').forEach(btn => btn.addEventListener('click', stop));
    overlay.querySelector('[data-mode-upgrade]')?.addEventListener('click', ctx.modeUsage.upgrade);
  }

  function bind(result, payload, index) {
    const overlay = document.getElementById('streamOverlay');
    bindGuideLayer(overlay);
    overlay.querySelectorAll('[data-stream-close]').forEach(btn => btn.addEventListener('click', stop));
    overlay.querySelector('[data-stream-prev]')?.addEventListener('click', () => render(payload, result, Math.max(0, index - 1)));
    overlay.querySelector('[data-stream-next]')?.addEventListener('click', () => render(payload, result, (index + 1) % payload.sequence.length));
    overlay.querySelector('[data-mode-audio]')?.addEventListener('click', () => {
      setGuideOpen(overlay, HUMAN_ID, true);
      setGuideOpen(overlay, NARRATION_ID, true);
      const node = result.nodes?.[index];
      const narration = index === 0
        ? [result.narration_intro, node?.narration_text].filter(Boolean).join(' ')
        : node?.narration_text;
      ctx.modeAudio.speak(narration || result.narration_intro || result.display_intro, 'STREAM', { aliases: result.speech_aliases || {} });
    });
    overlay.querySelectorAll('[data-stream-step]').forEach(btn => btn.addEventListener('click', () => render(payload, result, Number(btn.dataset.streamStep))));
    overlay.querySelectorAll('[data-stream-preset]').forEach(btn => btn.addEventListener('click', () => open({ seedRef: lastSeedRef, allEntries: lastAllEntries, preset: btn.dataset.streamPreset })));
  }

  async function open({ seedRef = null, allEntries = [], preset = 'dream' } = {}) {
    lastSeedRef = seedRef || lastSeedRef;
    lastAllEntries = allEntries.length ? allEntries : lastAllEntries;
    const gate = await ctx.modeUsage.check('stream');
    const length = gate.remaining === 'unlimited' ? (STREAM_PRESETS.find(p => p.id === preset)?.length || 6) : 3;
    const sequenceRefs = buildPath(lastSeedRef, lastAllEntries, preset, length);
    if (!sequenceRefs.length) {
      ctx.setStatus('STREAM WAITING FOR CODEX INDEX');
      return;
    }
    const sequence = sequenceRefs.map(collect);
    const payload = {
      title: `${STREAM_PRESETS.find(p => p.id === preset)?.title || 'Dream Logic'} Stream`,
      preset,
      sequence: sequence.map((node, index) => ({ ...node, why: sequenceRefs[index]?.why }))
    };
    renderLoading(payload);
    const result = await requestStructuredMode({
      feature: 'stream',
      prompt: buildStreamPrompt(payload),
      usage: ctx.modeUsage,
      fallback: () => fallback(payload),
      setStatus: ctx.setStatus
    });
    if (result.locked) renderLocked(result);
    else {
      controller = { result, payload, index: 0 };
      render(payload, result, 0);
      ctx.setStatus('INITIATORY STREAM OPEN');
    }
  }

  function next() {
    if (!controller) return;
    controller.index = (controller.index + 1) % controller.payload.sequence.length;
    render(controller.payload, controller.result, controller.index);
  }

  function prev() {
    if (!controller) return;
    controller.index = Math.max(0, controller.index - 1);
    render(controller.payload, controller.result, controller.index);
  }

  function stop() {
    ctx.modeAudio.stop();
    document.getElementById('streamOverlay')?.classList.remove('on');
    controller = null;
  }

  return { open, next, prev, stop };
}
