import { requestStructuredMode } from './mode-api.js';
import { buildSynthesisPrompt } from './prompt-schemas.js';
import { bindGuideLayer, renderTextLayer, setGuideOpen } from './guide-layer.js';
import { buildSynthesisFallback } from './mode-prose.js';

const TONES = ['oracle', 'mythic', 'alchemical', 'clinical-symbolic', 'xenolinguistic'];
const HUMAN_ID = 'synthesis-human';
const NARRATION_ID = 'synthesis-narration';

export function createSynthesisMode(ctx) {
  let current = null;
  let currentTone = 'mythic';

  function collect(cat, entry) {
    const name = ctx.getEntryName(cat, entry);
    return {
      system: cat,
      system_label: ctx.CAT_META[cat]?.label || cat,
      name,
      glyph: ctx.getGlyph(name, cat),
      color: ctx.getColorForEntry(name, cat),
      correspondences: ctx.fieldOrder(entry, true).map(key => ({
        system: key,
        label: ctx.CAT_META[key]?.label || key,
        value: entry[key]
      }))
    };
  }

  function fallback(payload) {
    return buildSynthesisFallback(payload, currentTone);
  }

  function normalizeResult(result) {
    return {
      ...result,
      display_text: result.display_text || result.short_reading || '',
      guide_text: result.guide_text || result.deep_reading || 'The human reading is pending for this chamber.',
      narration_text: result.narration_text || result.audio_text || 'The narration transcript is pending for this chamber.',
      speech_aliases: result.speech_aliases || {}
    };
  }

  function renderLoading(payload) {
    const overlay = document.getElementById('cardOverlay');
    overlay.innerHTML = `<div class="mode-chamber synthesis-chamber">
      <button class="card-close-btn mode-close" data-mode-close>X</button>
      <div class="mode-kicker">SYNTHESIS CHAMBER</div>
      <div class="mode-hero">
        <div class="mode-glyph" style="color:${payload.color}">${payload.glyph}</div>
        <div>
          <div class="mode-title">${ctx.escapeHTML(payload.name)}</div>
          <div class="mode-sub">${ctx.escapeHTML(payload.system_label)} / ${ctx.escapeHTML(currentTone.toUpperCase())} TONE</div>
        </div>
      </div>
      <div class="ritual-loader"><span></span><span></span><span></span></div>
      <div class="mode-copy">Drawing correspondence pressure through the lattice...</div>
    </div>`;
    overlay.classList.add('open');
    bindCommon();
  }

  function renderLocked(result) {
    const overlay = document.getElementById('cardOverlay');
    overlay.innerHTML = `<div class="mode-chamber synthesis-chamber">
      <button class="card-close-btn mode-close" data-mode-close>X</button>
      <div class="mode-kicker">INITIATE GATE</div>
      <div class="mode-title">The chamber is sealed for now.</div>
      <div class="mode-copy">Your ${ctx.escapeHTML(result.gate.plan)} synthesis allotment is complete. Create a free account for daily chamber access; Initiate unlocks narration, regenerate, and unlimited use.</div>
      <button class="mode-btn-primary" data-mode-upgrade>CREATE FREE ACCOUNT</button>
    </div>`;
    overlay.classList.add('open');
    bindCommon();
  }

  function renderResult(payload, result) {
    result = normalizeResult(result);
    const overlay = document.getElementById('cardOverlay');
    const tones = TONES.map(tone => `<button class="mode-chip ${tone === currentTone ? 'active' : ''}" data-tone="${tone}">${tone}</button>`).join('');
    const motifs = (result.motifs || []).map(item => `<span>${ctx.escapeHTML(item)}</span>`).join('');
    const canRegenerate = result.gate?.remaining === 'unlimited' || result.gate?.plan === 'admin';
    overlay.innerHTML = `<div class="mode-chamber synthesis-chamber">
      <button class="card-close-btn mode-close" data-mode-close>X</button>
      <div class="mode-kicker">SYNTHESIS CHAMBER</div>
      <div class="mode-hero">
        <div class="mode-glyph" style="color:${payload.color}">${payload.glyph}</div>
        <div>
          <div class="mode-title">${ctx.escapeHTML(result.title || payload.name)}</div>
          <div class="mode-sub">${ctx.escapeHTML(payload.system_label)} / ${ctx.escapeHTML((result.source || 'local').toUpperCase())}</div>
        </div>
      </div>
      <div class="mode-tone-row">${tones}</div>
      <div class="layer-caption">Primary Occult Text</div>
      <div class="mode-reading occult-display">${ctx.escapeHTML(result.display_text || '').replace(/\n/g, '<br><br>')}</div>
      ${renderTextLayer({ id: HUMAN_ID, label: 'Human Reading - Guide Translation', text: result.guide_text, open: true, variant: 'human' })}
      ${renderTextLayer({ id: NARRATION_ID, label: 'Narration Transcript', text: result.narration_text, open: true, variant: 'narration' })}
      <div class="mode-motifs">${motifs}</div>
      <div class="mode-actions">
        <button class="mode-btn-primary" data-mode-audio>PLAY NARRATION</button>
        <button class="mode-btn" data-mode-copy>COPY</button>
        <button class="mode-btn" data-mode-regenerate ${canRegenerate ? '' : 'disabled title="Regenerate unlocks with Initiate or admin test mode"'}>REGENERATE</button>
      </div>
      <div class="mode-quota">${formatGate(result.gate)}</div>
    </div>`;
    overlay.classList.add('open');
    bindCommon(result.narration_text, result.speech_aliases);
  }

  function formatGate(gate) {
    if (!gate) return '';
    if (gate.plan === 'admin') return 'Admin test mode / chambers unsealed';
    if (gate.remaining === 'unlimited') return 'Initiate access / unlimited chamber use';
    return `${gate.remaining} ${gate.feature} use${gate.remaining === 1 ? '' : 's'} remaining for ${gate.plan}`;
  }

  function bindCommon(audioText = '', aliases = {}) {
    const overlay = document.getElementById('cardOverlay');
    bindGuideLayer(overlay);
    overlay.querySelector('[data-mode-close]')?.addEventListener('click', ctx.closeOverlay);
    overlay.querySelector('[data-mode-upgrade]')?.addEventListener('click', ctx.modeUsage.upgrade);
    overlay.querySelector('[data-mode-audio]')?.addEventListener('click', () => {
      setGuideOpen(overlay, HUMAN_ID, true);
      setGuideOpen(overlay, NARRATION_ID, true);
      ctx.modeAudio.speak(audioText, 'SYNTHESIS', { aliases });
    });
    overlay.querySelector('[data-mode-copy]')?.addEventListener('click', () => {
      const copyText = [
        overlay.querySelector('.occult-display')?.textContent || '',
        overlay.querySelector(`[data-guide-body="${HUMAN_ID}"]`)?.textContent || '',
        overlay.querySelector(`[data-guide-body="${NARRATION_ID}"]`)?.textContent || ''
      ].filter(Boolean).join('\n\n');
      navigator.clipboard?.writeText(copyText || audioText || '');
      ctx.setStatus('SYNTHESIS COPIED');
    });
    overlay.querySelector('[data-mode-regenerate]')?.addEventListener('click', () => {
      if (current) open(current, currentTone, true);
    });
    overlay.querySelectorAll('[data-tone]').forEach(btn => {
      btn.addEventListener('click', () => {
        currentTone = btn.dataset.tone || 'mythic';
        if (current) open(current, currentTone, true);
      });
    });
  }

  async function open(target, tone = currentTone) {
    current = target;
    currentTone = tone;
    const payload = collect(target.cat, target.entry);
    renderLoading(payload);
    const prompt = buildSynthesisPrompt(payload, currentTone);
    const result = await requestStructuredMode({
      feature: 'synthesis',
      prompt,
      usage: ctx.modeUsage,
      fallback: () => fallback(payload),
      setStatus: ctx.setStatus
    });
    if (result.locked) renderLocked(result);
    else renderResult(payload, result);
  }

  return { open };
}
