const UT_SDK_URL = 'https://www.universal-transmissions.com/integration/UTIntegration.min.js';

const FEATURE_LIMITS = {
  admin: {
    synthesis: { scope: 'unlimited', limit: Infinity },
    resonance: { scope: 'unlimited', limit: Infinity },
    stream: { scope: 'unlimited', limit: Infinity },
    audio_generations: { scope: 'unlimited', limit: Infinity }
  },
  guest: {
    synthesis: { scope: 'lifetime', limit: 1 },
    resonance: { scope: 'lifetime', limit: 1 },
    stream: { scope: 'daily', limit: 1 },
    audio_generations: { scope: 'lifetime', limit: 0 }
  },
  free: {
    synthesis: { scope: 'daily', limit: 3 },
    resonance: { scope: 'daily', limit: 2 },
    stream: { scope: 'daily', limit: 1 },
    audio_generations: { scope: 'daily', limit: 0 }
  },
  initiate: {
    synthesis: { scope: 'unlimited', limit: Infinity },
    resonance: { scope: 'unlimited', limit: Infinity },
    stream: { scope: 'unlimited', limit: Infinity },
    audio_generations: { scope: 'unlimited', limit: Infinity }
  },
  master: {
    synthesis: { scope: 'unlimited', limit: Infinity },
    resonance: { scope: 'unlimited', limit: Infinity },
    stream: { scope: 'unlimited', limit: Infinity },
    audio_generations: { scope: 'unlimited', limit: Infinity }
  }
};

function todayKey() {
  return new Date().toISOString().slice(0, 10);
}

function uuid() {
  if (globalThis.crypto?.randomUUID) return globalThis.crypto.randomUUID();
  return `anon-${Date.now()}-${Math.random().toString(16).slice(2)}`;
}

function getAnonymousId() {
  const key = 'ut_codex_anonymous_id';
  let id = localStorage.getItem(key);
  if (!id) {
    id = window.getAnonymousId?.() || uuid();
    localStorage.setItem(key, id);
  }
  return id;
}

function storageKey(feature, scope, plan) {
  const suffix = scope === 'daily' ? todayKey() : 'lifetime';
  return `ut_codex_usage:v2:${plan}:${feature}:${suffix}`;
}

function isAdminMode() {
  return localStorage.getItem('ut_codex_admin_mode') === 'true';
}

function readCount(key) {
  return Number(localStorage.getItem(key) || 0);
}

function writeCount(key, count) {
  localStorage.setItem(key, String(count));
}

export function createModeUsage({ setStatus } = {}) {
  let sdkPromise = null;
  let planCache = null;

  async function loadSDK() {
    if (window.getUTOracle) return window.getUTOracle();
    if (!sdkPromise) {
      sdkPromise = new Promise((resolve, reject) => {
        const existing = document.querySelector(`script[src="${UT_SDK_URL}"]`);
        if (existing) {
          existing.addEventListener('load', () => resolve(window.getUTOracle?.()), { once: true });
          existing.addEventListener('error', reject, { once: true });
          return;
        }
        const script = document.createElement('script');
        script.src = UT_SDK_URL;
        script.async = true;
        script.onload = () => resolve(window.getUTOracle?.());
        script.onerror = reject;
        document.head.appendChild(script);
      });
    }
    const factory = await sdkPromise;
    return factory ? factory() : null;
  }

  async function getPlan() {
    if (isAdminMode()) return 'admin';
    if (planCache) return planCache;
    try {
      const ut = await loadSDK();
      if (ut?.currentUser?.plan) {
        planCache = ut.currentUser.plan;
        return planCache;
      }
      if (ut?.isLoggedIn && ut.getPlanStatus) {
        const status = await ut.getPlanStatus();
        planCache = status?.plan || 'free';
        return planCache;
      }
    } catch {
      // Local guest mode keeps the chamber usable without UT network availability.
    }
    planCache = 'guest';
    return planCache;
  }

  async function check(feature) {
    const plan = await getPlan();
    const config = FEATURE_LIMITS[plan]?.[feature] || FEATURE_LIMITS.guest[feature];
    if (!config || config.scope === 'unlimited') {
      return { allowed: true, plan, feature, used: 0, remaining: 'unlimited', limit: 'unlimited', scope: 'unlimited' };
    }
    const key = storageKey(feature, config.scope, plan);
    const used = readCount(key);
    return {
      allowed: used < config.limit,
      plan,
      feature,
      used,
      limit: config.limit,
      scope: config.scope,
      remaining: Math.max(0, config.limit - used)
    };
  }

  async function consume(feature) {
    const gate = await check(feature);
    if (!gate.allowed || gate.scope === 'unlimited') return gate;
    const key = storageKey(feature, gate.scope, gate.plan);
    writeCount(key, gate.used + 1);
    return { ...gate, used: gate.used + 1, remaining: Math.max(0, gate.limit - gate.used - 1) };
  }

  async function askOracle(prompt, options = {}) {
    const ut = await loadSDK();
    if (!ut?.askOracle) throw new Error('UT Oracle SDK unavailable');
    const anonymousId = ut.currentUser ? undefined : getAnonymousId();
    return ut.askOracle(prompt, {
      anonymousId,
      mode: options.mode || 'symbolic',
      language: options.language || 'en'
    });
  }

  async function upgrade() {
    try {
      const ut = await loadSDK();
      if (ut?.currentUser && ut.activateFreePlan) {
        await ut.activateFreePlan();
        clearPlanCache();
        setStatus?.('FREE ACCOUNT ACTIVE');
        return;
      }
      if (ut?.subscribeToInitiate) {
        window.open('https://www.universal-transmissions.com/oracle', '_blank', 'noopener');
        return;
      }
      if (ut?.startInitiateCheckout) {
        const url = await ut.startInitiateCheckout(window.location.href);
        window.location.href = url;
        return;
      }
    } catch (err) {
      setStatus?.('INITIATE GATEWAY UNAVAILABLE');
    }
    window.open('https://www.universal-transmissions.com/oracle', '_blank', 'noopener');
  }

  function setAdminMode(enabled) {
    localStorage.setItem('ut_codex_admin_mode', enabled ? 'true' : 'false');
    clearPlanCache();
  }

  function resetUsage() {
    Object.keys(localStorage)
      .filter(key => key.startsWith('ut_codex_usage:'))
      .forEach(key => localStorage.removeItem(key));
    clearPlanCache();
  }

  function clearPlanCache() {
    planCache = null;
  }

  return { check, consume, askOracle, upgrade, getPlan, clearPlanCache, setAdminMode, resetUsage, isAdminMode };
}
