export const SYNTHESIS_SCHEMA = {
  mode: 'ORACLE | MYTHIC | ALCHEMICAL | CLINICAL_SYMBOLIC | XENOLINGUISTIC',
  title: 'string',
  spoken_title: 'string',
  display_text: 'string',
  guide_text: 'string',
  narration_text: 'string',
  speech_aliases: { raw_label: 'spoken label' },
  motifs: ['string']
};

export const RESONANCE_SCHEMA = {
  title: 'string',
  spoken_title_left: 'string',
  spoken_title_right: 'string',
  mode: 'harmony | tension | mirror | transformation',
  shared_fields: [{ field: 'string', values: ['string'] }],
  frictions: [{ field: 'string', left: 'string', right: 'string' }],
  hidden_bridges: ['string'],
  display_text: 'string',
  guide_text: 'string',
  narration_text: 'string',
  speech_aliases: { raw_label: 'spoken label' }
};

export const STREAM_SCHEMA = {
  stream_title: 'string',
  stream_subtitle: 'string',
  display_intro: 'string',
  guide_intro: 'string',
  narration_intro: 'string',
  nodes: [{
    node_name: 'string',
    spoken_name: 'string',
    display_text: 'string',
    guide_text: 'string',
    narration_text: 'string',
    transition_reason: 'string'
  }],
  closing_line: 'string',
  speech_aliases: { raw_label: 'spoken label' }
};

function compactPayload(payload) {
  return JSON.stringify(payload, null, 2).slice(0, 9000);
}

const GLOBAL_TEXT_RULES = `GLOBAL TEXT ARCHITECTURE:
Return three genuinely different texts. They must not be near-duplicates.
1. display_text: occult-facing, compressed, chamber-worthy, symbolic, elegant.
2. guide_text: human-readable, psychologically and emotionally legible, not tiny filler, not boilerplate.
3. narration_text: spoken transcript, story-driven, natural aloud, emotionally intelligent, never raw database speech.

Never start with reusable wrappers like "In human terms..." or "This pairing shows..." unless the sentence is rewritten with specific content from the actual entry.
If the first one or two sentences could fit any entry, the output fails.
Select the strongest 5-10 correspondences for coherence. Do not mention everything.
Priority: planet/zodiac/element/tarot; then geometry/body/chakra/kabbalah/number/frequency; then metals/crystals/plants; then deity/rune/I Ching/geomancy/letters.
Never narrate glyphs, emojis, zodiac icons, bracket metadata, semicolon chains, or raw labels.
Normalize speech aliases such as "Ares [OTHER]" -> "Ares", "ROOT-MULADHARA" -> "the root chakra", "XIX - The Sun" -> "The Sun".`;

const SYNTHESIS_STYLES = {
  oracle: 'ORACLE: revelatory, luminous, compressive, elegant, like a symbolic seer speaking clearly.',
  mythic: 'MYTHIC: archetypal, deity-facing, story-rich, image-driven, dramatic, presence-oriented.',
  alchemical: 'ALCHEMICAL: process-driven; vessel, heat, dissolution, conjunction, fixation, metals, cooking, transformation.',
  'clinical-symbolic': 'CLINICAL_SYMBOLIC: psychologically and physiologically grounded, precise, embodied, intelligent, less mystical haze.',
  xenolinguistic: 'XENOLINGUISTIC: naming, utterance, glyph, letter, threshold-language, semantic and sonic intelligence.'
};

const RESONANCE_STYLES = {
  harmony: 'HARMONY: convergence, complementarity, shared field becoming form.',
  tension: 'TENSION: friction, competing values, drives, pressures, unresolved heat.',
  mirror: 'MIRROR: reflection, inversion, one force revealing the hidden truth of the other.',
  transformation: 'TRANSFORMATION: contact creates a third thing; emergence and transmutation through encounter.'
};

const STREAM_STYLES = {
  dream: 'DREAM_LOGIC: surreal, intuitive, emotionally coherent; transitions by hidden resemblance.',
  chakra: 'CHAKRA_ASCENT: developmental, embodied, rising through body, psyche, voice, sight, and spirit.',
  planetary: 'PLANETARY_DESCENT: celestial force descending into embodiment, law, gravity, consequence.',
  elemental: 'ELEMENTAL_TRANSFORMATION: alchemical sequence; what is broken, softened, hardened, purified, or changed.'
};

export function buildSynthesisPrompt(payload, tone = 'mythic') {
  return `Return only valid JSON matching this schema: ${JSON.stringify(SYNTHESIS_SCHEMA)}.
${GLOBAL_TEXT_RULES}

MODE: SYNTHESIS.
STYLE CONTRACT: ${SYNTHESIS_STYLES[tone] || SYNTHESIS_STYLES.mythic}
Length targets:
- display_text: 180-320 words.
- guide_text: 100-220 words.
- narration_text: 350-700 words.

The display layer may remain mysterious. The guide layer must make the symbol understandable in lived terms. The narration layer must sound authored for a human voice, not assembled from fields.

ENTRY PAYLOAD:
${compactPayload(payload)}`;
}

export function buildResonancePrompt(payload, mode = 'harmony') {
  return `Return only valid JSON matching this schema: ${JSON.stringify(RESONANCE_SCHEMA)}.
${GLOBAL_TEXT_RULES}

MODE: RESONANCE CHAMBER.
STYLE CONTRACT: ${RESONANCE_STYLES[mode] || RESONANCE_STYLES.harmony}
Length targets:
- display_text: 220-380 words.
- guide_text: 120-260 words.
- narration_text: 450-850 words.

Stage this as a meaningful encounter between two symbolic beings. Shared fields, frictions, and hidden bridges must remain visible in the JSON and must inform the prose. Do not write a spreadsheet diff.

RESONANCE PAYLOAD:
${compactPayload(payload)}`;
}

export function buildStreamPrompt(payload) {
  const preset = String(payload.preset || 'dream').toLowerCase();
  return `Return only valid JSON matching this schema: ${JSON.stringify(STREAM_SCHEMA)}.
${GLOBAL_TEXT_RULES}

MODE: INITIATORY STREAM.
STYLE CONTRACT: ${STREAM_STYLES[preset] || STREAM_STYLES.dream}
Length targets:
- display_intro: 20-80 words.
- guide_intro: 80-180 words.
- narration_intro: 140-260 words.
- each node display_text: 8-30 words.
- each node guide_text: 30-80 words.
- each node narration_text: 80-160 words.

Explain what kind of journey this is, why it matters in human life, why each node leads to the next, and what transformation is underway. It must feel like a guided symbolic pilgrimage, not a coded itinerary.

STREAM PAYLOAD:
${compactPayload(payload)}`;
}
